import * as React from 'react';
import { useCascaderData } from './useCascaderData';
import useCascade from './useCascade';
import { CascadeContextProvider } from './CascadeContext';
import { CascadeUI } from './cascadeUI';
import type { CascadeProps } from './interface';
import type { CascadeRef } from '../interface';

export const Cascade = React.forwardRef<CascadeRef, CascadeProps>((props, ref) => {
  const { options = [] } = props;

  const { doublyTreeNodeMap, doublyTreeNodeList } = useCascaderData({
    options,
  });

  const cascadeCtxValue = useCascade(
    props,
    {
      doublyTreeNodeMap,
      doublyTreeNodeList,
    },
    ref,
  );

  return (
    <CascadeContextProvider value={cascadeCtxValue}>
      <CascadeUI />
    </CascadeContextProvider>
  );
});

export default Cascade;
